exercises.solution_code:
#include <array>
#include <cstddef>
#include <iostream>

template <typename T, std::size_t N>
T arraySum(const std::array<T, N>& arr, std::size_t count)
{
    T sum{};
    for (std::size_t i{ 0 }; i < count; ++i)
        sum += arr[i];
    return sum;
}

int main()
{
    std::array<int, 5> arr{};
    std::size_t n{};
    std::cin >> n;

    for (std::size_t i{ 0 }; i < n; ++i)
        std::cin >> arr[i];

    int sum{ arraySum(arr, n) };
    std::cout << "Sum: " << sum << '\n';
    std::cout << "Avg: " << sum / static_cast<int>(n) << '\n';

    return 0;
}

