#include <array>
#include <cstddef>
#include <iostream>

std::array<int, 5> buildRow(int multiplier)
{
    std::array<int, 5> row{};
    for (std::size_t i{ 0 }; i < 5; ++i)
        row[i] = multiplier * static_cast<int>(i + 1);
    return row;
}

template <typename T, std::size_t N>
void printArray(const std::array<T, N>& arr)
{
    for (std::size_t i{ 0 }; i < N; ++i)
    {
        if (i > 0)
            std::cout << ' ';
        std::cout << arr[i];
    }
    std::cout << '\n';
}

int main()
{
    int m{};
    std::cin >> m;

    auto row{ buildRow(m) };
    printArray(row);

    return 0;
}
